   324→                    }
   325→                    flag = true;
   326→                    if (min > t_hit)
   327→                    {
   328→                        min = t_hit;
   329→                        triangle_index = i;
   330→                    }
   331→                }
   332→            }
   333→        }
   334→        else if (ignore == 0 || light == 1)
